  1â†’package main
  2â†’
  3â†’import (
  4â†’	"context"
  5â†’	"flag"
  6â†’	"fmt"
  7â†’	"log/slog"
  8â†’	"time"
  9â†’
 10â†’	"github.com/jackc/pgx/v5/pgxpool"
 11â†’	"github.com/ketang/kapow/tools/kapow/internal/config"
 12â†’	"github.com/ketang/kapow/tools/kapow/internal/fetch"
 13â†’)
 14â†’
 15â†’// Importer defines the interface that all data importers must implement.
 16â†’type Importer interface {
 17â†’	// Name returns the subcommand name (e.g. "nces", "rankings").
 18â†’	Name() string
 19â†’	// Description returns a short human-readable description.
 20â†’	Description() string
 21â†’	// Dependencies returns names of importers that must run before this one.
 22â†’	Dependencies() []string
 23â†’	// RegisterFlags adds importer-specific flags to the given FlagSet.
 24â†’	RegisterFlags(fs *flag.FlagSet)
 25â†’	// Run executes the import. It may use the pool for DB operations and the
 26â†’	// fetcher for downloading source data.
 27â†’	Run(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher) error
 28â†’}
 29â†’
 30â†’// registry holds all registered importers keyed by name.
 31â†’var registry = map[string]Importer{}
 32â†’
 33â†’// Register adds an importer to the registry. Panics on duplicate name.
 34â†’func Register(imp Importer) {
 35â†’	name := imp.Name()
 36â†’	if _, exists := registry[name]; exists {
 37â†’		panic(fmt.Sprintf("importer: duplicate registration: %s", name))
 38â†’	}
 39â†’	registry[name] = imp
 40â†’}
 41â†’
 42â†’// Get returns a registered importer by name, or nil if not found.
 43â†’func Get(name string) Importer {
 44â†’	return registry[name]
 45â†’}
 46â†’
 47â†’// All returns all registered importers.
 48â†’func All() map[string]Importer {
 49â†’	return registry
 50â†’}
 51â†’
 52â†’// RunAll executes all importers in dependency order.
 53â†’func RunAll(ctx context.Context, cfg *config.Config, pool *pgxpool.Pool, fetcher *fetch.Fetcher, skip, only map[string]bool) error {
 54â†’	ordered, err := topoSort(registry)
 55â†’	if err != nil {
 56â†’		return err
 57â†’	}
 58â†’
 59â†’	for _, imp := range ordered {
 60â†’		name := imp.Name()
 61â†’		if len(only) > 0 && !only[name] {
 62â†’			slog.Info("run-all: skipping (not in --only)", "importer", name)
 63â†’			continue
 64â†’		}
 65â†’		if skip[name] {
 66â†’			slog.Info("run-all: skipping (in --skip)", "importer", name)
 67â†’			continue
 68â†’		}
 69â†’
 70â†’		slog.Info("run-all: starting", "importer", name)
 71â†’		start := time.Now()
 72â†’		if err := imp.Run(ctx, cfg, pool, fetcher); err != nil {
 73â†’			return fmt.Errorf("run-all: %s: %w", name, err)
 74â†’		}
 75â†’		slog.Info("run-all: completed", "importer", name, "duration", time.Since(start).Round(time.Millisecond))
 76â†’	}
 77â†’
 78â†’	return nil
 79â†’}
 80â†’
 81â†’// topoSort returns importers in dependency order using Kahn's algorithm.
 82â†’func topoSort(importers map[string]Importer) ([]Importer, error) {
 83â†’	// Build in-degree map and adjacency list.
 84â†’	inDegree := make(map[string]int)
 85â†’	dependents := make(map[string][]string) // dep -> list of importers that depend on it
 86â†’
 87â†’	for name, imp := range importers {
 88â†’		if _, ok := inDegree[name]; !ok {
 89â†’			inDegree[name] = 0
 90â†’		}
 91â†’		for _, dep := range imp.Dependencies() {
 92â†’			inDegree[name]++
 93â†’			dependents[dep] = append(dependents[dep], name)
 94â†’		}
 95â†’	}
 96â†’
 97â†’	// Start with importers that have no dependencies.
 98â†’	var queue []string
 99â†’	for name, deg := range inDegree {
100â†’		if deg == 0 {
101â†’			queue = append(queue, name)
102â†’		}
103â†’	}
104â†’
105â†’	var result []Importer
106â†’	for len(queue) > 0 {
107â†’		name := queue[0]
108â†’		queue = queue[1:]
109â†’		if imp, ok := importers[name]; ok {
110â†’			result = append(result, imp)
111â†’		}
112â†’		for _, dep := range dependents[name] {
113â†’			inDegree[dep]--
114â†’			if inDegree[dep] == 0 {
115â†’				queue = append(queue, dep)
116â†’			}
117â†’		}
118â†’	}
119â†’
120â†’	if len(result) != len(importers) {
121â†’		return nil, fmt.Errorf("importer: circular dependency detected")
122â†’	}
123â†’
124â†’	return result, nil
125â†’}
