  1â†’package ranking
  2â†’
  3â†’import (
  4â†’	"context"
  5â†’	"encoding/json"
  6â†’	"fmt"
  7â†’	"log/slog"
  8â†’	"math"
  9â†’	"strconv"
 10â†’	"strings"
 11â†’
 12â†’	"github.com/jackc/pgx/v5/pgxpool"
 13â†’	"github.com/ketang/kapow/tools/kapow/internal/dbutil"
 14â†’)
 15â†’
 16â†’// Opinion represents a single ranking observation for one institution from one
 17â†’// publication/category in a given year.
 18â†’type Opinion struct {
 19â†’	PublicationSlug string
 20â†’	CategorySlug    string
 21â†’	Method          string  // "rank", "score", "tier", "range"
 22â†’	Year            int
 23â†’	UnitID          string
 24â†’	Rank            int
 25â†’	Score           float64
 26â†’	Tier            string
 27â†’}
 28â†’
 29â†’// PublicationMeta holds display metadata for a ranking publication+category.
 30â†’type PublicationMeta struct {
 31â†’	PublicationSlug string
 32â†’	Publication     string // display name
 33â†’	CategorySlug    string
 34â†’	Category        string // display name
 35â†’	URL             string
 36â†’}
 37â†’
 38â†’// rankingID returns the deterministic key used across ranking tables and the
 39â†’// institution JSONB column. Format: "pub_slug____cat_slug".
 40â†’func rankingID(pubSlug, catSlug string) string {
 41â†’	return pubSlug + "____" + catSlug
 42â†’}
 43â†’
 44â†’// RankingBuilder accumulates Opinion values and publication metadata, then
 45â†’// batch-writes them to the database via Flush.
 46â†’type RankingBuilder struct {
 47â†’	opinions     []Opinion
 48â†’	publications map[string]PublicationMeta // keyed by rankingID
 49â†’}
 50â†’
 51â†’// NewBuilder creates an empty RankingBuilder.
 52â†’func NewBuilder() *RankingBuilder {
 53â†’	return &RankingBuilder{
 54â†’		publications: make(map[string]PublicationMeta),
 55â†’	}
 56â†’}
 57â†’
 58â†’// SetPublication registers display metadata for a publication+category pair.
 59â†’func (b *RankingBuilder) SetPublication(pubSlug, pubName, catSlug, catName, url string) {
 60â†’	id := rankingID(pubSlug, catSlug)
 61â†’	b.publications[id] = PublicationMeta{
 62â†’		PublicationSlug: pubSlug,
 63â†’		Publication:     pubName,
 64â†’		CategorySlug:    catSlug,
 65â†’		Category:        catName,
 66â†’		URL:             url,
 67â†’	}
 68â†’}
 69â†’
 70â†’// Add appends an opinion to the builder.
 71â†’func (b *RankingBuilder) Add(op Opinion) {
 72â†’	b.opinions = append(b.opinions, op)
 73â†’}
 74â†’
 75â†’// Len returns the number of accumulated opinions.
 76â†’func (b *RankingBuilder) Len() int {
 77â†’	return len(b.opinions)
 78â†’}
 79â†’
 80â†’// Flush writes all accumulated data to the database:
 81â†’//  1. Upserts ranking metadata into search_base.ranking
 82â†’//  2. Upserts per-year data into search_base.annual_dataset (theme=RANKING)
 83â†’//  3. Merges latest-year rankings into institution.rankings JSONB
 84â†’func (b *RankingBuilder) Flush(ctx context.Context, pool *pgxpool.Pool) error {
 85â†’	if len(b.opinions) == 0 {
 86â†’		return nil
 87â†’	}
 88â†’
 89â†’	// Step 1: upsert ranking metadata
 90â†’	if err := b.flushRankingMeta(ctx, pool); err != nil {
 91â†’		return err
 92â†’	}
 93â†’
 94â†’	// Step 2: upsert annual datasets
 95â†’	if err := b.flushAnnualDatasets(ctx, pool); err != nil {
 96â†’		return err
 97â†’	}
 98â†’
 99â†’	// Step 3: merge into institution.rankings JSONB
100â†’	if err := b.flushInstitutionRankings(ctx, pool); err != nil {
101â†’		return err
102â†’	}
103â†’
104â†’	slog.Info("ranking: flushed", "opinions", len(b.opinions), "publications", len(b.publications))
105â†’	return nil
106â†’}
107â†’
108â†’func (b *RankingBuilder) flushRankingMeta(ctx context.Context, pool *pgxpool.Pool) error {
109â†’	const upsertSQL = `
110â†’INSERT INTO search_base.ranking (id, publication_slug, publication, category_slug, category, url)
111â†’VALUES ($1, $2, $3, $4, $5, $6)
112â†’ON CONFLICT (id) DO UPDATE SET
113â†’    publication = EXCLUDED.publication,
114â†’    category    = EXCLUDED.category,
115â†’    url         = EXCLUDED.url`
116â†’
117â†’	queries := make([]dbutil.BatchQuery, 0, len(b.publications))
118â†’	for id, pm := range b.publications {
119â†’		queries = append(queries, dbutil.BatchQuery{
120â†’			SQL:  upsertSQL,
121â†’			Args: []any{id, pm.PublicationSlug, pm.Publication, pm.CategorySlug, pm.Category, pm.URL},
122â†’		})
123â†’	}
124â†’	if err := dbutil.BatchExec(ctx, pool, queries); err != nil {
125â†’		return fmt.Errorf("ranking: flush ranking meta: %w", err)
126â†’	}
127â†’	return nil
128â†’}
129â†’
130â†’func (b *RankingBuilder) flushAnnualDatasets(ctx context.Context, pool *pgxpool.Pool) error {
131â†’	const batchSize = 500
132â†’	for i := 0; i < len(b.opinions); i += batchSize {
133â†’		end := i + batchSize
134â†’		if end > len(b.opinions) {
135â†’			end = len(b.opinions)
136â†’		}
137â†’		if err := b.flushAnnualDatasetBatch(ctx, pool, b.opinions[i:end]); err != nil {
138â†’			return err
139â†’		}
140â†’	}
141â†’	return nil
142â†’}
143â†’
144â†’func (b *RankingBuilder) flushAnnualDatasetBatch(ctx context.Context, pool *pgxpool.Pool, opinions []Opinion) error {
145â†’	for _, op := range opinions {
146â†’		data := buildOpinionData(op)
147â†’		dataJSON, err := json.Marshal(data)
148â†’		if err != nil {
149â†’			return fmt.Errorf("ranking: marshal annual dataset: %w", err)
150â†’		}
151â†’		ads := &dbutil.AnnualDataset{
152â†’			UnitID:  op.UnitID,
153â†’			Year:    op.Year,
154â†’			Theme:   "RANKING",
155â†’			Datakey: rankingID(op.PublicationSlug, op.CategorySlug),
156â†’			Data:    dataJSON,
157â†’		}
158â†’		if err := dbutil.UpsertAnnualDataset(ctx, pool, ads); err != nil {
159â†’			return fmt.Errorf("ranking: flush annual dataset: %w", err)
160â†’		}
161â†’	}
162â†’	return nil
163â†’}
164â†’
165â†’// buildOpinionData returns the JSONB payload for an opinion.
166â†’func buildOpinionData(op Opinion) map[string]any {
167â†’	d := map[string]any{
168â†’		"method": op.Method,
169â†’	}
170â†’	switch op.Method {
171â†’	case "rank":
172â†’		d["rank"] = op.Rank
173â†’	case "score":
174â†’		d["score"] = op.Score
175â†’	case "tier":
176â†’		d["tier"] = op.Tier
177â†’	case "range":
178â†’		d["rank"] = op.Rank
179â†’		d["tier"] = op.Tier
180â†’	}
181â†’	return d
182â†’}
183â†’
184â†’func (b *RankingBuilder) flushInstitutionRankings(ctx context.Context, pool *pgxpool.Pool) error {
185â†’	// Group opinions by unit_id, keeping only the latest year per ranking.
186â†’	type key struct {
187â†’		unitID    string
188â†’		rankingID string
189â†’	}
190â†’	latest := make(map[key]Opinion)
191â†’	for _, op := range b.opinions {
192â†’		k := key{unitID: op.UnitID, rankingID: rankingID(op.PublicationSlug, op.CategorySlug)}
193â†’		if existing, ok := latest[k]; !ok || op.Year > existing.Year {
194â†’			latest[k] = op
195â†’		}
196â†’	}
197â†’
198â†’	// Group by unit_id to build per-institution JSONB.
199â†’	byUnit := make(map[string]map[string]any)
200â†’	for k, op := range latest {
201â†’		if byUnit[k.unitID] == nil {
202â†’			byUnit[k.unitID] = make(map[string]any)
203â†’		}
204â†’		byUnit[k.unitID][k.rankingID] = buildOpinionData(op)
205â†’	}
206â†’
207â†’	for unitID, rankings := range byUnit {
208â†’		rankingsJSON, err := json.Marshal(rankings)
209â†’		if err != nil {
210â†’			return fmt.Errorf("ranking: marshal institution rankings: %w", err)
211â†’		}
212â†’		inst := &dbutil.Institution{
213â†’			UnitID:   unitID,
214â†’			Rankings: rankingsJSON,
215â†’		}
216â†’		if err := dbutil.UpsertInstitution(ctx, pool, inst); err != nil {
217â†’			return fmt.Errorf("ranking: flush institution rankings: %w", err)
218â†’		}
219â†’	}
220â†’	return nil
221â†’}
222â†’
223â†’// DeriveOpinion parses a raw ranking string and returns the method, rank,
224â†’// score, and tier. Supported formats:
225â†’//   - Numeric ranks: "1", "42"
226â†’//   - Tier strings: "Tier 1", "Tier 2"
227â†’//   - Ranges: "201-300" (rank = midpoint, tier = original string)
228â†’//   - Decimal scores: "78.5"
229â†’func DeriveOpinion(raw string) (method string, rank int, score float64, tier string, err error) {
230â†’	raw = strings.TrimSpace(raw)
231â†’	if raw == "" {
232â†’		return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: empty input")
233â†’	}
234â†’
235â†’	// Tier format: "Tier N" or "Tier ..."
236â†’	if strings.HasPrefix(strings.ToLower(raw), "tier") {
237â†’		return "tier", 0, 0, raw, nil
238â†’	}
239â†’
240â†’	// Range format: "NNN-NNN"
241â†’	if parts := strings.SplitN(raw, "-", 2); len(parts) == 2 {
242â†’		lo, errLo := strconv.Atoi(strings.TrimSpace(parts[0]))
243â†’		hi, errHi := strconv.Atoi(strings.TrimSpace(parts[1]))
244â†’		if errLo == nil && errHi == nil && lo > 0 && hi > 0 {
245â†’			midpoint := int(math.Round(float64(lo+hi) / 2))
246â†’			return "range", midpoint, 0, raw, nil
247â†’		}
248â†’	}
249â†’
250â†’	// Integer rank
251â†’	if n, errInt := strconv.Atoi(raw); errInt == nil {
252â†’		return "rank", n, 0, "", nil
253â†’	}
254â†’
255â†’	// Decimal score
256â†’	if f, errFloat := strconv.ParseFloat(raw, 64); errFloat == nil {
257â†’		return "score", 0, f, "", nil
258â†’	}
259â†’
260â†’	return "", 0, 0, "", fmt.Errorf("ranking: derive opinion: unrecognized format %q", raw)
261â†’}
