 13â†’func TestMergeJSONB(t *testing.T) {
 14â†’	tests := []struct {
 15â†’		name    string
 16â†’		dst     []byte
 17â†’		src     []byte
 18â†’		want    map[string]any
 19â†’		wantErr bool
 20â†’	}{
 21â†’		{
 22â†’			name: "both nil",
 23â†’			dst:  nil,
 24â†’			src:  nil,
 25â†’			want: map[string]any{},
 26â†’		},
 27â†’		{
 28â†’			name: "dst nil src has data",
 29â†’			dst:  nil,
 30â†’			src:  []byte(`{"a":1}`),
 31â†’			want: map[string]any{"a": float64(1)},
 32â†’		},
 33â†’		{
 34â†’			name: "src nil dst has data",
 35â†’			dst:  []byte(`{"a":1}`),
 36â†’			src:  nil,
 37â†’			want: map[string]any{"a": float64(1)},
 38â†’		},
 39â†’		{
 40â†’			name: "no overlap",
 41â†’			dst:  []byte(`{"a":1}`),
 42â†’			src:  []byte(`{"b":2}`),
 43â†’			want: map[string]any{"a": float64(1), "b": float64(2)},
 44â†’		},
 45â†’		{
 46â†’			name: "src overwrites dst on conflict",
 47â†’			dst:  []byte(`{"a":1,"b":2}`),
 48â†’			src:  []byte(`{"b":99,"c":3}`),
 49â†’			want: map[string]any{"a": float64(1), "b": float64(99), "c": float64(3)},
 50â†’		},
 51â†’		{
 52â†’			name: "empty objects",
 53â†’			dst:  []byte(`{}`),
 54â†’			src:  []byte(`{}`),
 55â†’			want: map[string]any{},
 56â†’		},
 57â†’		{
 58â†’			name:    "invalid dst",
 59â†’			dst:     []byte(`not-json`),
 60â†’			src:     []byte(`{"a":1}`),
 61â†’			wantErr: true,
 62â†’		},
 63â†’		{
 64â†’			name:    "invalid src",
 65â†’			dst:     []byte(`{"a":1}`),
 66â†’			src:     []byte(`not-json`),
 67â†’			wantErr: true,
 68â†’		},
 69â†’	}
 70â†’
 71â†’	for _, tc := range tests {
 72â†’		t.Run(tc.name, func(t *testing.T) {
 73â†’			got, err := MergeJSONB(tc.dst, tc.src)
 74â†’			if tc.wantErr {
 75â†’				if err == nil {
 76â†’					t.Fatal("expected error, got nil")
 77â†’				}
 78â†’				return
 79â†’			}
 80â†’			if err != nil {
 81â†’				t.Fatalf("unexpected error: %v", err)
 82â†’			}
 83â†’
 84â†’			var gotMap map[string]any
 85â†’			if err := json.Unmarshal(got, &gotMap); err != nil {
 86â†’				t.Fatalf("output is not valid JSON: %v", err)
 87â†’			}
 88â†’
 89â†’			if len(gotMap) != len(tc.want) {
 90â†’				t.Fatalf("got %d keys, want %d: %v", len(gotMap), len(tc.want), gotMap)
 91â†’			}
 92â†’			for k, wantVal := range tc.want {
 93â†’				gotVal, ok := gotMap[k]
 94â†’				if !ok {
 95â†’					t.Errorf("missing key %q", k)
 96â†’					continue
 97â†’				}
 98â†’				if fmt.Sprintf("%v", gotVal) != fmt.Sprintf("%v", wantVal) {
 99â†’					t.Errorf("key %q: got %v, want %v", k, gotVal, wantVal)
100â†’				}
101â†’			}
102â†’		})
103â†’	}
104â†’}
